func (f *bootstrapGmailFake) handle(w http.ResponseWriter, r *http.Request) {
	if strings.HasSuffix(r.URL.Path, "/users/me/messages") {
		label := r.URL.Query().Get("labelIds")
		if label == "" && strings.Contains(r.URL.Query().Get("q"), "-label:inbox") {
			label = "ARCHIVED"
		}
		ids := f.messages[label]
		maxResults, _ := strconv.Atoi(r.URL.Query().Get("maxResults"))
		if maxResults <= 0 || maxResults > len(ids) {
			maxResults = len(ids)
		}
		refs := make([]map[string]string, 0, maxResults)
		for _, id := range ids[:maxResults] {
			refs = append(refs, map[string]string{"id": id, "threadId": "thread-" + id})
		}
		body, _ := json.Marshal(map[string]any{
			"messages":           refs,
			"resultSizeEstimate": len(ids),
		})
		_, _ = w.Write(body)
		return
	}
	if strings.Contains(r.URL.Path, "/users/me/messages/") {
		parts := strings.Split(r.URL.Path, "/")
		id := parts[len(parts)-1]
		_, _ = w.Write([]byte(bootstrapMessageFixture(id)))
		return
	}
	http.Error(w, "unexpected path "+r.URL.String(), 404)
}

func bootstrapMessageFixture(id string) string {
	body := strings.TrimRight(base64.URLEncoding.EncodeToString([]byte("body for "+id)), "=")
	fixture := map[string]any{
		"id":           id,
		"threadId":     "thread-" + id,
		"labelIds":     []string{"INBOX"},
		"snippet":      "snippet " + id,
		"historyId":    "hist-" + id,
		"internalDate": "1700000000000",
		"payload": map[string]any{
			"headers": []map[string]string{
				{"name": "From", "value": "alice@example.com"},
				{"name": "To", "value": "bob@example.com"},
				{"name": "Subject", "value": "Subject " + id},
				{"name": "Message-ID", "value": "<" + id + "@example.com>"},
			},
			"parts": []map[string]any{
				{
					"mimeType": "text/plain",
					"body":     map[string]any{"size": len("body for " + id), "data": body},
				},
			},
		},
	}
	data, _ := json.Marshal(fixture)
	return string(data)
}

func TestBootstrap_PerFolderLimitStoresMessagesAndHistory(t *testing.T) {
	fake := newBootstrapGmailFake(t)
	withGmailBaseURL(t, fake.srv.URL)

	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
	dbPath := filepath.Join(t.TempDir(), "data.db")

	stdout, _, err := executeCmd(t, "--config", configPath, "--agent", "--json", "bootstrap", "--folders", "inbox", "--per-folder", "2", "--db", dbPath)
	if err != nil {
		t.Fatalf("bootstrap: %v", err)
	}
	if !strings.Contains(stdout, `"event":"bootstrap_progress"`) {
		t.Fatalf("stdout missing progress event: %s", stdout)
	}

	s, err := store.Open(dbPath)
	if err != nil {
		t.Fatalf("open db: %v", err)
	}
	defer s.Close()
	var count int
	if err := s.DB().QueryRow(`SELECT COUNT(*) FROM messages WHERE account_email = 'user@example.com'`).Scan(&count); err != nil {
		t.Fatalf("count messages: %v", err)
	}
	if count != 2 {
		t.Fatalf("message count = %d want 2", count)
	}
	var ftsCount int
	if err := s.DB().QueryRow(`SELECT COUNT(*) FROM messages_fts WHERE messages_fts MATCH 'Subject'`).Scan(&ftsCount); err != nil {
		t.Fatalf("query fts: %v", err)
	}
	if ftsCount != 2 {
		t.Fatalf("fts count = %d want 2", ftsCount)
	}
	var historyCount int
	if err := s.DB().QueryRow(`SELECT COUNT(*) FROM history_state WHERE account_email = 'user@example.com' AND last_history_id <> ''`).Scan(&historyCount); err != nil {
		t.Fatalf("count history_state: %v", err)
	}
	if historyCount != 1 {
		t.Fatalf("history_state count = %d want 1", historyCount)
	}

	if _, _, err := executeCmd(t, "--config", configPath, "bootstrap", "--folders", "inbox", "--per-folder", "2", "--db", dbPath); err != nil {
		t.Fatalf("second bootstrap: %v", err)
	}
	if err := s.DB().QueryRow(`SELECT COUNT(*) FROM messages WHERE account_email = 'user@example.com'`).Scan(&count); err != nil {
		t.Fatalf("count messages after second run: %v", err)
	}
	if count != 2 {
		t.Fatalf("message count after idempotent rerun = %d want 2", count)
	}
}

func TestBootstrapFullClearsPreviousAccountState(t *testing.T) {
	fake := newBootstrapGmailFake(t)
	withGmailBaseURL(t, fake.srv.URL)

	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
	dbPath := filepath.Join(t.TempDir(), "data.db")

	if _, _, err := executeCmd(t, "--config", configPath, "bootstrap", "--folders", "inbox", "--per-folder", "1", "--db", dbPath); err != nil {
		t.Fatalf("initial bootstrap: %v", err)
	}
	fake.messages["INBOX"] = []string{"new-1"}
	if _, _, err := executeCmd(t, "--config", configPath, "bootstrap", "--folders", "inbox", "--per-folder", "1", "--full", "--db", dbPath); err != nil {
		t.Fatalf("full bootstrap: %v", err)
	}

	s, err := store.Open(dbPath)
	if err != nil {
		t.Fatalf("open db: %v", err)
	}
	defer s.Close()
	var oldCount, newCount int
	if err := s.DB().QueryRow(`SELECT COUNT(*) FROM messages WHERE id = 'inbox-1'`).Scan(&oldCount); err != nil {
		t.Fatalf("count old: %v", err)
	}
	if err := s.DB().QueryRow(`SELECT COUNT(*) FROM messages WHERE id = 'new-1'`).Scan(&newCount); err != nil {
		t.Fatalf("count new: %v", err)
	}
	if oldCount != 0 || newCount != 1 {
		t.Fatalf("post-full counts old=%d new=%d, want 0/1", oldCount, newCount)
	}
}

func TestBootstrapInvalidFolderUsageError(t *testing.T) {
	configPath, _ := withConfigPath(t)
	_, _, err := executeCmd(t, "--config", configPath, "bootstrap", "--folders", "nonexistent")
	if err == nil {
		t.Fatalf("expected invalid folder error")
	}
	if got := ExitCode(err); got != 2 {
		t.Fatalf("exit code = %d want 2", got)
	}
	if !strings.Contains(err.Error(), "valid:") || !strings.Contains(err.Error(), "inbox") {
		t.Fatalf("error missing valid folders: %v", err)
	}
}

// TestMaxHistoryID pins the greptile-bootstrap-history-checkpoint helper.
// Gmail's historyId is a stringified uint64, so a lex comparison would put
// "9" above "100". maxHistoryID must compare numerically and tolerate empty
// inputs (so first-folder accumulation works).
func TestMaxHistoryID(t *testing.T) {
	cases := []struct {
		name string
		a, b string
		want string
	}{
		{"numeric a > b", "100", "9", "100"},
		{"numeric b > a", "9", "100", "100"},
		{"equal", "42", "42", "42"},
		{"empty a", "", "5", "5"},
		{"empty b", "5", "", "5"},
		{"both empty", "", "", ""},
		{"large values cross 32 bit", "5000000000", "4294967296", "5000000000"},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if got := maxHistoryID(tc.a, tc.b); got != tc.want {
				t.Fatalf("maxHistoryID(%q, %q) = %q, want %q", tc.a, tc.b, got, tc.want)
			}
		})
	}
}
